class Solution {
public:
    bool canConstruct(string s, int k) {
        if (s.length() < k) return false;
        unordered_map<char, int> count;
        for (char c : s) count[c]++;
        int odd = 0;
        for (auto& pair : count) {
            if (pair.second % 2 != 0) odd++;
        }
        return odd <= k;
    }
};
